CREATE DATABASE IF NOT EXISTS family_tree_db;
USE family_tree_db;
SET NAMES utf8mb4;

SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS activitylog;
DROP TABLE IF EXISTS livestream;
DROP TABLE IF EXISTS media;
DROP TABLE IF EXISTS media_album;
DROP TABLE IF EXISTS spouse_relation;
DROP TABLE IF EXISTS person;
DROP TABLE IF EXISTS family_tree;
DROP TABLE IF EXISTS user_role;
DROP TABLE IF EXISTS `user`;
DROP TABLE IF EXISTS `role`;
DROP TABLE IF EXISTS branch;

SET FOREIGN_KEY_CHECKS = 1;

-- ROLE
CREATE TABLE `role` (
                        `id` bigint(20) NOT NULL AUTO_INCREMENT,
                        `name` varchar(255) NOT NULL,
                        `code` varchar(255) NOT NULL,
                        `createddate` datetime DEFAULT NULL,
                        `modifieddate` datetime DEFAULT NULL,
                        `createdby` varchar(255) DEFAULT NULL,
                        `modifiedby` varchar(255) DEFAULT NULL,
                        PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

INSERT INTO `role` (`id`, `name`, `code`, `createddate`, `modifieddate`, `createdby`, `modifiedby`) VALUES
