-- Build spouse relation graph for multi-spouse rendering
INSERT INTO `spouse_relation` (
    `left_person_id`, `right_person_id`, `relation_order`, `relation_label`,
    `createddate`, `modifieddate`, `createdby`, `modifiedby`
)
SELECT
    LEAST(p.`id`, s.`id`),
    GREATEST(p.`id`, s.`id`),
    NULL,
    NULL,
    NOW(),
    NOW(),
    'xlsx_spouse_relation_seed',
    'xlsx_spouse_relation_seed'
FROM `person` p
JOIN `person` s ON p.`spouse_id` = s.`id`
WHERE p.`spouse_id` IS NOT NULL
  AND p.`id` < s.`id`
ON DUPLICATE KEY UPDATE
    `modifieddate` = VALUES(`modifieddate`),
    `modifiedby` = VALUES(`modifiedby`);

